mapper.select:
        SELECT COUNT(*)
        FROM PROJECT p


		        p.project_title LIKE '%' || #{keyword} || '%'



		        AND (
		            NOT EXISTS (
		                SELECT 1 FROM members m3
		                WHERE m3.project_id = p.project_id
		            )
		            OR EXISTS (
		                SELECT 1 FROM members m2
		                JOIN users u2 ON m2.user_code = u2.user_code
		                WHERE m2.project_id = p.project_id
		                  AND u2.company_id = #{companyId}
		            )
		        )


		        AND EXISTS (
		            SELECT 1 FROM members m
		            WHERE m.project_id = p.project_id
		              AND m.user_code = #{userCode}
		        )

SELECT COUNT(*)
FROM project
WHERE project_identifier = #{projectIdentifier}

SELECT module_name
FROM module_mapping
WHERE project_id = #{projectId}

mapper.insert:
INSERT INTO module_mapping( module_map_id, project_id, module_name ) SELECT (SELECT NVL(MAX(module_map_id), 0) FROM module_mapping) + ROWNUM, t.project_id, t.module_name FROM (
SELECT #{projectId} AS project_id, #{name} AS module_name FROM dual
) t
